import { forwardRef, useMemo } from "react";

import { useContainerWidth } from "../hooks";
import StaticPhotoAlbum from "../../static";
import resolveMasonryProps from "./resolveMasonryProps";
import computeMasonryLayout from "../../layouts/masonry";
import type { ElementRef, ForwardedRef, JSXElement, MasonryPhotoAlbumProps, Photo } from "../../types";

function MasonryPhotoAlbum<TPhoto extends Photo>(
  { photos, breakpoints, defaultContainerWidth, ...rest }: MasonryPhotoAlbumProps<TPhoto>,
  ref: ForwardedRef,
) {
  const { containerRef, containerWidth } = useContainerWidth(ref, breakpoints, defaultContainerWidth);

  const { spacing, padding, columns, ...restProps } = resolveMasonryProps(containerWidth, { photos, ...rest });

  const model = useMemo(
    () =>
      containerWidth !== undefined && spacing !== undefined && padding !== undefined && columns !== undefined
        ? computeMasonryLayout(photos, spacing, padding, containerWidth, columns)
        : undefined,
    [photos, spacing, padding, containerWidth, columns],
  );

  return <StaticPhotoAlbum layout="masonry" ref={containerRef} model={model} {...restProps} />;
}

export default forwardRef(MasonryPhotoAlbum) as <TPhoto extends Photo>(
  props: MasonryPhotoAlbumProps<TPhoto> & ElementRef,
) => JSXElement;

import { resolveCommonProps, resolveResponsiveParameter } from "../../utils";
import type { ComponentsProps, MasonryPhotoAlbumProps, Photo, Render, ResolvedNumber } from "../../types";

type ResolvedMasonryProps<TPhoto extends Photo, TWidth extends number | undefined = number | undefined> = Omit<
  MasonryPhotoAlbumProps<TPhoto>,
  "columns" | "spacing" | "padding" | "componentsProps" | "render"
> & {
  spacing: ResolvedNumber<TWidth>;
  padding: ResolvedNumber<TWidth>;
  columns: ResolvedNumber<TWidth>;
  componentsProps: ComponentsProps<TPhoto>;
  render: Render<TPhoto> | undefined;
};

export default function resolveMasonryProps<TPhoto extends Photo>(
  containerWidth: number,
  props: MasonryPhotoAlbumProps<TPhoto>,
): ResolvedMasonryProps<TPhoto, number>;

export default function resolveMasonryProps<TPhoto extends Photo>(
  containerWidth: number | undefined,
  props: MasonryPhotoAlbumProps<TPhoto>,
): ResolvedMasonryProps<TPhoto>;

export default function resolveMasonryProps<TPhoto extends Photo>(
  containerWidth: number | undefined,
  { columns, ...rest }: MasonryPhotoAlbumProps<TPhoto>,
) {
  return {
    ...rest,
    ...resolveCommonProps(containerWidth, rest),
    columns: resolveResponsiveParameter(columns, containerWidth, [5, 4, 3, 2], 1),
  };
}

import { ratio } from "../../utils";
import type { LayoutModel, Photo } from "../../types";

export default function computeMasonryLayout<TPhoto extends Photo>(
  photos: readonly TPhoto[],
  spacing: number,
  padding: number,
  containerWidth: number,
  columns: number,
): LayoutModel<TPhoto> | undefined {
  // calculate column width based on total width and columns count
  const columnWidth = (containerWidth - spacing * (columns - 1) - 2 * padding * columns) / columns;

  // encountered impossible layout
  if (columnWidth <= 0) {
    // will try to find a solution recursively with fewer columns
    return columns > 1 ? computeMasonryLayout(photos, spacing, padding, containerWidth, columns - 1) : undefined;
  }

  // store current top positions for each column
  const columnsCurrentTopPositions: number[] = [];
  for (let i = 0; i < columns; i += 1) {
    columnsCurrentTopPositions[i] = 0;
  }

  // group photos by column
  const columnsModel = photos.reduce<{ photo: TPhoto; index: number }[][]>(
    (model, photo, index) => {
      // find the shortest column
      const shortestColumn = columnsCurrentTopPositions.reduce(
        (currentShortestColumn, item, i) =>
          // subtracting 1 here to compensate for floating point precision errors
          // when two columns have identical height their floating point values can be slightly off
          // in subsequent re-renders, leading to images jumping between columns
          item < columnsCurrentTopPositions[currentShortestColumn] - 1 ? i : currentShortestColumn,
        0,
      );

      // update top position of the shortest column
      columnsCurrentTopPositions[shortestColumn] =
        columnsCurrentTopPositions[shortestColumn] + columnWidth / ratio(photo) + spacing + 2 * padding;

      // place a photo into the shortest column
      model[shortestColumn].push({ photo, index });

      return model;
    },
    Array.from({ length: columns }, () => []),
  );

  // map through each column and photo and add layout properties
  return {
    spacing,
    padding,
    containerWidth,
    variables: { columns },
    tracks: columnsModel.map((column) => ({
      photos: column.map(({ photo, index }) => ({
        photo,
        index,
        width: columnWidth,
        height: columnWidth / ratio(photo),
      })),
    })),
  };
}

.react-photo-album--masonry {
  justify-content: space-between;

  & .react-photo-album--track {
    flex-direction: column;
    justify-content: flex-start;
    row-gap: calc(var(--react-photo-album--spacing) * 1px);

    width: calc(
      (100% - var(--react-photo-album--spacing) * 1px * (var(--react-photo-album--columns) - 1)) /
        var(--react-photo-album--columns)
    );
  }

  & .react-photo-album--photo {
    width: 100%;
  }
}

import { useState } from "react";

export default function useArray<T>(array: readonly T[] | undefined) {
  const [state, setState] = useState(array);

  if (
    array !== state &&
    (!array || !state || array.length !== state.length || array.some((el, i) => el !== state[i]))
  ) {
    setState(array);
    return array;
  }

  return state;
}

import { useCallback, useReducer, useRef } from "react";

import useArray from "./useArray";
import type { ForwardedRef } from "../../types";

// Maximum expected scrollbar width in pixels, used to distinguish
// scrollbar-induced resize oscillation from legitimate container resizes.
const MAX_SCROLLBAR_WIDTH = 20;

type State = [containerWidth?: number, prevContainerWidth?: number];

function containerWidthReducer(state: State, newContainerWidth: number | undefined): State {
  const [containerWidth, prevContainerWidth] = state;

  if (containerWidth === newContainerWidth) {
    return state;
  }

  // Detect resize loop caused by scrollbar appearance/disappearance: when rendering
  // at width A causes content overflow (scrollbar appears, shrinking width to B), and
  // rendering at width B removes the overflow (scrollbar disappears, restoring width A),
  // the container width oscillates between A and B indefinitely. Settle on the smaller
  // width to break the cycle — the layout fits within the scrollbar-reduced width,
  // preventing further oscillation.
  if (
    prevContainerWidth !== undefined &&
    newContainerWidth !== undefined &&
    containerWidth !== undefined &&
    newContainerWidth === prevContainerWidth &&
    Math.abs(newContainerWidth - containerWidth) <= MAX_SCROLLBAR_WIDTH
  ) {
    const min = Math.min(containerWidth, newContainerWidth);
    const max = Math.max(containerWidth, newContainerWidth);
    // preserve state reference to avoid unnecessary re-renders
    return min === containerWidth && max === prevContainerWidth ? state : [min, max];
  }

  return [newContainerWidth, containerWidth];
}

function resolveContainerWidth(el: HTMLElement | null, breakpoints: readonly number[] | undefined) {
  let width = el?.clientWidth;
  if (width !== undefined && breakpoints && breakpoints.length > 0) {
    const sorted = [...breakpoints.filter((x) => x > 0)].sort((a, b) => b - a);
    sorted.push(Math.floor(sorted[sorted.length - 1] / 2));
    width = sorted.find((breakpoint, index) => breakpoint <= width! || index === sorted.length - 1);
  }
  return width;
}

export default function useContainerWidth(
  ref: ForwardedRef,
  breakpointsArray: readonly number[] | undefined,
  defaultContainerWidth?: number,
) {
  const [[containerWidth], dispatch] = useReducer(containerWidthReducer, [defaultContainerWidth]);
  const breakpoints = useArray(breakpointsArray);
  const observerRef = useRef<ResizeObserver>(undefined);

  const containerRef = useCallback(
    // eslint-disable-next-line react-hooks/immutability -- false-positive lint
    (node: HTMLElement | null) => {
      observerRef.current?.disconnect();
      observerRef.current = undefined;

      const updateWidth = () => dispatch(resolveContainerWidth(node, breakpoints));

      updateWidth();

      if (node && typeof ResizeObserver !== "undefined") {
        observerRef.current = new ResizeObserver(updateWidth);
        observerRef.current.observe(node);
      }

      if (typeof ref === "function") {
        ref(node);
      } else if (ref) {
        // eslint-disable-next-line react-hooks/immutability -- false-positive lint
        ref.current = node;
      }
    },
    [ref, breakpoints],
  );

  return { containerRef, containerWidth };
}

import type React from "react";
import { forwardRef } from "react";

import { clsx, cssClass, cssVar, round } from "../utils";
import type { LayoutVariables, RenderFunction } from "../types";

type BaseProps<TComponent extends React.ElementType> = Pick<
  React.ComponentProps<TComponent>,
  "children" | "style" | "className"
>;

type PolymorphicRef<Component extends React.ElementType> = React.ComponentPropsWithRef<Component>["ref"];

type ElementProps<
  TComponent extends React.ElementType,
  TContext extends object | void,
  TRenderProps extends BaseProps<TComponent>,
> = Partial<TRenderProps> &
  Omit<React.ComponentProps<TComponent>, keyof TRenderProps> & {
    as?: TComponent;
    render?: RenderFunction<TRenderProps, TContext>;
    context?: TContext;
    classes?: string | (string | undefined)[];
    variables?: LayoutVariables;
  };

function Component<
  TComponent extends React.ElementType,
  TContext extends object | void,
  TRenderProps extends BaseProps<TComponent>,
>(
  {
    as,
    render,
    context,
    classes = [],
    variables = {},
    style: styleProp,
    className: classNameProp,
    children,
    ...rest
  }: ElementProps<TComponent, TContext, TRenderProps>,
  ref: PolymorphicRef<TComponent>,
) {
  const className = clsx(
    ...(Array.isArray(classes) ? classes : [classes]).filter((el) => typeof el === "string").map(cssClass),
    classNameProp,
  );

  const style = {
    ...Object.fromEntries(
      Object.entries(variables).map(([key, value]) => [
        cssVar(key.replace(/([a-z])([A-Z])/g, "$1-$2").toLowerCase()),
        typeof value === "number" ? round(value, 5) : value,
      ]),
    ),
    ...styleProp,
  };

  const props = { style, className, children, ...rest };

  if (render) {
    // eslint-disable-next-line react-hooks/refs -- false-positive lint
    const rendered = render({ ref, ...props } as unknown as TRenderProps, context as TContext);
    if (rendered) return rendered;
  }

  const Element: any = as || "div";
  return <Element ref={ref} {...props} />;
}

export default forwardRef(Component) as <
  TComponent extends React.ElementType,
  TContext extends object | void,
  TRenderProps extends BaseProps<TComponent>,
>(
  props: ElementProps<TComponent, TContext, TRenderProps> & { ref?: PolymorphicRef<TComponent> },
) => React.ReactNode;

import type React from "react";
import { forwardRef } from "react";

import Component from "./Component";
import { round } from "../utils";
import type {
  ComponentsProps,
  ElementRef,
  ForwardedRef,
  JSXElement,
  Photo,
  Render,
  RenderPhotoContext,
  RenderPhotoProps,
} from "../types";

// eslint-disable-next-line @typescript-eslint/no-explicit-any
type Unwrap<T> = T extends (args: any) => unknown ? never : T;

type Unwrapped<T> = {
  [P in keyof T]: Unwrap<T[P]>;
};

type PhotoComponentProps<TPhoto extends Photo> = RenderPhotoProps &
  RenderPhotoContext<TPhoto> & {
    render?: Pick<Render<TPhoto>, "wrapper" | "link" | "button" | "image" | "extras">;
    componentsProps?: Unwrapped<Pick<ComponentsProps<TPhoto>, "wrapper" | "link" | "button" | "image">>;
  };

function PhotoComponent<TPhoto extends Photo>(
  {
    photo,
    index,
    width,
    height,
    onClick,
    render: { wrapper, link, button, image, extras } = {},
    componentsProps: { link: linkProps, button: buttonProps, wrapper: wrapperProps, image: imageProps } = {},
  }: PhotoComponentProps<TPhoto>,
  ref: ForwardedRef,
) {
  const { href } = photo;

  const context = { photo, index, width: round(width, 3), height: round(height, 3) };

  let props: Omit<React.ComponentPropsWithoutRef<typeof Component>, "variables">;
  if (href) {
    props = { ...linkProps, as: "a", render: link, classes: ["photo", "link"], href, onClick };
  } else if (onClick) {
    props = { ...buttonProps, as: "button", type: "button", render: button, classes: ["photo", "button"], onClick };
  } else {
    props = { ...wrapperProps, render: wrapper, classes: "photo" };
  }

  return (
    <Component
      ref={ref}
      variables={{ photoWidth: context.width, photoHeight: context.height }}
      {...{ context, ...props }}
    >
      <Component as="img" classes="image" render={image} context={context} {...imageProps} />
      {extras?.({}, context)}
    </Component>
  );
}

export default forwardRef(PhotoComponent) as <TPhoto extends Photo>(
  props: PhotoComponentProps<TPhoto> & ElementRef,
) => JSXElement;

import type React from "react";
import { forwardRef } from "react";

import Component from "./Component";
import PhotoComponent from "./PhotoComponent";
import { srcSetAndSizes, unwrap } from "../utils";
import type { CommonPhotoAlbumProps, ComponentsProps, ElementRef, LayoutModel, Photo, Render } from "../types";

export type StaticPhotoAlbumProps<TPhoto extends Photo> = Pick<
  CommonPhotoAlbumProps<TPhoto>,
  "sizes" | "onClick" | "skeleton"
> & {
  layout?: string;
  model?: LayoutModel<TPhoto>;
  render?: Render<TPhoto>;
  componentsProps?: ComponentsProps<TPhoto>;
};

function StaticPhotoAlbum<TPhoto extends Photo>(
  {
    layout,
    sizes,
    model,
    skeleton,
    onClick: onClickCallback,
    render: { container, track, photo: renderPhoto, ...restRender } = {},
    componentsProps: {
      container: containerProps,
      track: trackProps,
      link: linkProps,
      button: buttonProps,
      wrapper: wrapperProps,
      image: imageProps,
    } = {},
  }: StaticPhotoAlbumProps<TPhoto>,
  ref: React.ForwardedRef<HTMLElement>,
) {
  const { spacing, padding, containerWidth, tracks, variables, horizontal } = model || {};

  return (
    <Component
      role="group"
      aria-label="Photo album"
      {...containerProps}
      variables={{ spacing, padding, containerWidth, ...variables }}
      classes={["", layout]}
      render={container}
      ref={ref}
    >
      {spacing !== undefined &&
        padding !== undefined &&
        containerWidth !== undefined &&
        tracks?.map(({ photos, variables: trackVariables }, trackIndex) => {
          const trackSize = photos.length;
          const photosCount = horizontal ? trackSize : tracks.length;

          return (
            <Component
              {...trackProps}
              key={trackIndex}
              render={track}
              classes="track"
              variables={{ trackSize, ...trackVariables }}
            >
              {photos.map((context) => {
                const { photo, index, width } = context;
                const { key, src, alt = "", title, label } = photo;

                const onClick = onClickCallback
                  ? (event: React.MouseEvent) => {
                      onClickCallback({ event, photo, index });
                    }
                  : undefined;

                if (renderPhoto) {
                  const rendered = renderPhoto({ onClick }, context);
                  if (rendered) return rendered;
                }

                const ariaLabel = <T extends object | undefined>(props: T) => {
                  return label ? { "aria-label": label, ...props } : props;
                };

                return (
                  <PhotoComponent
                    // index is always unique; src can collide when the same photo appears multiple times
                    key={key ?? index}
                    onClick={onClick}
                    render={restRender}
                    componentsProps={{
                      image: {
                        // loading="lazy" must precede src and srcSet
                        loading: "lazy" as const,
                        decoding: "async" as const,
                        src,
                        alt,
                        title,
                        ...srcSetAndSizes(photo, sizes, width, containerWidth, photosCount, spacing, padding),
                        ...unwrap(imageProps, context),
                      },
                      link: ariaLabel(unwrap(linkProps, context)),
                      button: ariaLabel(unwrap(buttonProps, context)),
                      wrapper: unwrap(wrapperProps, context),
                    }}
                    {...context}
                  />
                );
              })}
            </Component>
          );
        })}

      {containerWidth === undefined && skeleton}
    </Component>
  );
}

export default forwardRef(StaticPhotoAlbum) as <TPhoto extends Photo>(
  props: StaticPhotoAlbumProps<TPhoto> & ElementRef,
) => React.ReactNode;

import type React from "react";

/** Layout type */
export type LayoutType = "rows" | "columns" | "masonry";

/** Photo object */
export interface Photo extends Image {
  /** React `key` attribute. */
  key?: string;
  /** Image `alt` attribute. */
  alt?: string;
  /** Image `title` attribute. */
  title?: string;
  /** Image link URL. */
  href?: string;
  /** ARIA label for the link and button elements */
  label?: string;
  /** Optional array of alternative images to be included in the `srcset` attribute. */
  srcSet?: readonly Image[];
}

/** Image object */
export interface Image {
  /** Image source. */
  src: string;
  /** Image width in pixels. */
  width: number;
  /** Image height in pixels. */
  height: number;
}

/** Common photo album props */
export interface CommonPhotoAlbumProps<TPhoto extends Photo = Photo> {
  /** An array of photos to display in the photo album. */
  photos: readonly TPhoto[];
  /** Spacing between images. */
  spacing?: ResponsiveParameter;
  /** Padding around each image. */
  padding?: ResponsiveParameter;
  /** Photo album container width in various viewports. */
  sizes?: ResponsiveSizes;
  /** Photo album layout breakpoints. */
  breakpoints?: readonly number[];
  /** Default container width in SSR. */
  defaultContainerWidth?: number;
  /** Photo click callback. */
  onClick?: ClickHandler<TPhoto>;
  /** Custom render functions. */
  render?: ResponsiveParameter<Render<TPhoto>, number | undefined>;
  /** Additional HTML attributes to be passed to the rendered elements. */
  componentsProps?: ResponsiveParameter<ComponentsProps<TPhoto>, number | undefined>;
  /** Fallback skeleton in SSR. */
  skeleton?: React.ReactNode;
}

/** Rows photo album props */
export interface RowsPhotoAlbumProps<TPhoto extends Photo = Photo> extends CommonPhotoAlbumProps<TPhoto> {
  /** Target row height. */
  targetRowHeight?: ResponsiveParameter;
  /** Additional row constraints. */
  rowConstraints?: ResponsiveParameter<RowConstraints>;
}

/** Columns photo album props */
export interface ColumnsPhotoAlbumProps<TPhoto extends Photo = Photo> extends CommonPhotoAlbumProps<TPhoto> {
  /** Number of columns. */
  columns?: ResponsiveParameter;
}

/** Masonry photo album props */
// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface MasonryPhotoAlbumProps<TPhoto extends Photo = Photo> extends ColumnsPhotoAlbumProps<TPhoto> {}

/** Photo album sizes settings */
export type ResponsiveSizes = {
  /** Default size, e.g. `100vw` or `calc(100vw - 200px)`. */
  size: string;
  /** Array of sizes at various breakpoints. */
  sizes?: readonly {
    /** Viewport size media query, e.g. `(max-width: 600px)`.  */
    viewport: string;
    /** Photo album width at a given viewport size, e.g. `calc(100vw - 50px)`. */
    size: string;
  }[];
};

/** Row constraints */
export type RowConstraints = {
  /** Minimum number of photos per row. */
  minPhotos?: number;
  /** Maximum number of photos per row. */
  maxPhotos?: number;
  /** Maximum row height when there is not enough photos to fill more than one row. */
  singleRowMaxHeight?: number;
};

/** Layout model */
export type LayoutModel<TPhoto extends Photo = Photo> = {
  /** Spacing value. */
  spacing: number;
  /** Padding value. */
  padding: number;
  /** Container width. */
  containerWidth: number;
  /** Layout variables. */
  variables?: LayoutVariables;
  /** Layout orientation. */
  horizontal?: boolean;
  /** Layout tracks. */
  tracks: readonly {
    /** Track variables. */
    variables?: LayoutVariables;
    /** Photos array. */
    photos: readonly {
      /** Photo object. */
      photo: TPhoto;
      /** Photo index in the original `photos` array. */
      index: number;
      /** Rendered photo width in pixels. */
      width: number;
      /** Rendered photo height in pixels. */
      height: number;
    }[];
  }[];
};

/** Layout variables */
export type LayoutVariables = Record<string, string | number | undefined>;

/** Responsive parameter */
export type ResponsiveParameter<Value = number, ContainerWidth = number> =
  | ((containerWidth: ContainerWidth) => Value)
  | Value;

/** Components props */
export type ComponentsProps<TPhoto extends Photo = Photo> = {
  /** Additional HTML attributes for the outer `<div>` container. */
  container?: ContainerComponentProps;
  /** Additional HTML attributes for the row / column `<div>` container. */
  track?: TrackComponentProps;
  /** Additional HTML attributes for the image `<div>` wrapper. */
  wrapper?: WrapperComponentProps<TPhoto>;
  /** Additional HTML attributes for the photo `<a>` link. */
  link?: LinkComponentProps<TPhoto>;
  /** Additional HTML attributes for the photo `<button>` element. */
  button?: ButtonComponentProps<TPhoto>;
  /** Additional HTML attributes for the photo `<img>` element. */
  image?: ImageComponentProps<TPhoto>;
};

/** Container component props */
export type ContainerComponentProps = React.ComponentPropsWithoutRef<"div">;

/** Track component props */
export type TrackComponentProps = React.ComponentPropsWithoutRef<"div">;

/** Wrapper component props */
export type WrapperComponentProps<TPhoto extends Photo = Photo> = ContextAware<
  React.ComponentPropsWithoutRef<"div">,
  RenderWrapperContext<TPhoto>
>;

/** Link component props */
export type LinkComponentProps<TPhoto extends Photo = Photo> = ContextAware<
  React.ComponentPropsWithoutRef<"a">,
  RenderLinkContext<TPhoto>
>;

/** Button component props */
export type ButtonComponentProps<TPhoto extends Photo = Photo> = ContextAware<
  React.ComponentPropsWithoutRef<"button">,
  RenderButtonContext<TPhoto>
>;

/** Image component props */
export type ImageComponentProps<TPhoto extends Photo = Photo> = ContextAware<
  React.ComponentPropsWithoutRef<"img">,
  RenderImageContext<TPhoto>
>;

/** Click handler */
export type ClickHandler<TPhoto extends Photo = Photo> = (props: ClickHandlerProps<TPhoto>) => void;

/** Click callback props */
export type ClickHandlerProps<TPhoto extends Photo = Photo> = {
  /** Click event. */
  event: React.MouseEvent;
  /** Photo object. */
  photo: TPhoto;
  /** Photo index in the original `photos` array. */
  index: number;
};

/** Custom render functions */
export type Render<TPhoto extends Photo = Photo> = {
  /** Custom container render function. */
  container?: RenderContainer;
  /** Custom track render function. */
  track?: RenderTrack;
  /** Custom wrapper render function. */
  wrapper?: RenderWrapper<TPhoto>;
  /** Custom link render function. */
  link?: RenderLink<TPhoto>;
  /** Custom button render function. */
  button?: RenderButton<TPhoto>;
  /** Custom image render function. */
  image?: RenderImage<TPhoto>;
  /** Custom photo render function. */
  photo?: RenderPhoto<TPhoto>;
  /** Custom extra markup render function. */
  extras?: RenderExtras<TPhoto>;
};

/** Render container */
export type RenderContainer = RenderFunction<RenderContainerProps>;

/** Render container props */
export type RenderContainerProps = React.ComponentPropsWithRef<"div">;

/** Render track */
export type RenderTrack = RenderFunction<RenderTrackProps>;

/** Render track props */
export type RenderTrackProps = React.ComponentPropsWithoutRef<"div">;

/** Render wrapper */
export type RenderWrapper<TPhoto extends Photo = Photo> = RenderFunction<
  RenderWrapperProps,
  RenderWrapperContext<TPhoto>
>;

/** Render wrapper props */
export type RenderWrapperProps = React.ComponentPropsWithoutRef<"div">;

/** Render wrapper context */
export type RenderWrapperContext<TPhoto extends Photo = Photo> = RenderPhotoContext<TPhoto>;

/** Render link */
export type RenderLink<TPhoto extends Photo = Photo> = RenderFunction<RenderLinkProps, RenderLinkContext<TPhoto>>;

/** Render link props */
export type RenderLinkProps = NonOptional<React.ComponentPropsWithoutRef<"a">, "href">;

/** Render link context */
export type RenderLinkContext<TPhoto extends Photo = Photo> = RenderPhotoContext<TPhoto>;

/** Render button */
export type RenderButton<TPhoto extends Photo = Photo> = RenderFunction<RenderButtonProps, RenderButtonContext<TPhoto>>;

/** Render button props */
export type RenderButtonProps = React.ComponentPropsWithoutRef<"button">;

/** Render button context */
export type RenderButtonContext<TPhoto extends Photo = Photo> = RenderPhotoContext<TPhoto>;

/** Render image */
export type RenderImage<TPhoto extends Photo = Photo> = RenderFunction<RenderImageProps, RenderImageContext<TPhoto>>;

/** Render image props */
export type RenderImageProps = NonOptional<React.ComponentPropsWithoutRef<"img">, "src">;

/** Render image context */
export type RenderImageContext<TPhoto extends Photo = Photo> = RenderPhotoContext<TPhoto>;

/** Render photo */
export type RenderPhoto<TPhoto extends Photo = Photo> = RenderFunction<RenderPhotoProps, RenderPhotoContext<TPhoto>>;

/** Render photo props */
export type RenderPhotoProps = {
  /** Click callback. */
  onClick?: React.MouseEventHandler;
};

/** Render photo context */
export type RenderPhotoContext<TPhoto extends Photo = Photo> = {
  /** Photo object. */
  photo: TPhoto;
  /** Photo index in the original `photos` array. */
  index: number;
  /** Rendered photo width in pixels. */
  width: number;
  /** Rendered photo height in pixels. */
  height: number;
};

/** Render extras */
export type RenderExtras<TPhoto extends Photo = Photo> = RenderFunction<object, RenderPhotoContext<TPhoto>>;

/** Render function */
export type RenderFunction<Props extends object | void = void, Context extends object | void = void> = [
  Context,
] extends [void]
  ? [Props] extends [void]
    ? () => React.ReactNode
    : (
        /** Component props. */
        props: Props,
      ) => React.ReactNode
  : [Props] extends [void]
    ? never
    : (
        /** Component props. */
        props: Props,
        /** Rendering context. */
        context: Context,
      ) => React.ReactNode;

export type ResolvedNumber<TWidth extends number | undefined = number | undefined> = TWidth extends number
  ? number
  : number | undefined;

